        for i in range(3):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = 'W'
                self.board[7-i][7-j] = 'B'

    def print_board(self):
        for row in self.board:
            print(' '.join(row or '-'))

    def make_move(self, from_pos, to_pos):
        start_x, start_y = map(int, from_pos.split('-'))
        end_x, end_y = map(int, to_pos.split('-'))
        if self.board[start_x][start_y] and self.board[end_x][end_y] is None:
            self.board[end_x][end_y] = self.board[start_x][start_y]
            self.board[start_x][start_y] = None
            return True
        return False

    def check_win(self):
        # Simple win condition: one player has no pieces left
        if sum(row.count(None) for row in self.board) == 32:
            return 'Draw'
        if sum(row.count('W') for row in self.board) == 0:
            return 'Black wins'
        if sum(row.count('B') for row in self.board) == 0:
            return 'White wins'
        return None

